() => {
  const trigger = document.querySelector('otto-web-tool-bar-toggle-button[data-qa-id="uploadDrivers"], otto-web-tool-bar-toggle-button[data-qa-id="uploadCondutores"]');
  const menu = document.querySelector('gs-menu#cdk-menu-1') || document.querySelector('gs-menu[id^="cdk-menu-"]');
  if (!trigger || !menu) return;

  const wrap = menu.closest('.cdk-overlay-connected-position-bounding-box');
  if (wrap) {
    wrap.style.cssText = 'position:fixed;left:0;top:0;width:100vw;height:100vh;display:block;transform:none;pointer-events:none;';
  }

  const pane = menu.closest('.cdk-overlay-pane');
  if (pane) {
    pane.style.cssText = 'position:fixed;transform:none;pointer-events:none;';
  }

  const triggerRect = trigger.getBoundingClientRect();
  const menuRect = menu.getBoundingClientRect();
  const left = Math.round(triggerRect.left + (triggerRect.width / 2) - (menuRect.width / 2));
  const top = Math.round(triggerRect.bottom + 8);
  const target = pane || menu;
  target.style.left = left + 'px';
  target.style.top = top + 'px';
  target.style.margin = '0';

  const items = menu.querySelectorAll('button[role="menuitem"]');
  const hovered = items[1];
  if (hovered) {
    hovered.style.background = '#464a6c';
    hovered.style.color = '#efefef';
  }
}
